<?php
$emergencyWhere = $_SESSION['USER_TYPE'] === 'Admin' ? '' : " AND (emergency_request.created_by=:user_id OR emergency_request.receiver_id=:user_id OR emergency_request.reference_id=:user_id)";
$emergencySql = "SELECT emergency_request.*,project_information.name AS project_name,store_information.name AS store_name,receiver.name_en AS receiver_name,reference_person.name_en AS reference_name,creator.name_en AS creator_name,COUNT(emergency_request_detail.id) AS item_count,SUM(emergency_request_detail.issued_quantity) AS total_quantity FROM emergency_request INNER JOIN project_information ON project_information.id=emergency_request.project_id INNER JOIN store_information ON store_information.id=emergency_request.store_id INNER JOIN employee_information receiver ON receiver.id=emergency_request.receiver_id INNER JOIN employee_information reference_person ON reference_person.id=emergency_request.reference_id LEFT JOIN employee_information creator ON creator.id=emergency_request.created_by LEFT JOIN emergency_request_detail ON emergency_request_detail.emergency_request_id=emergency_request.id WHERE emergency_request.deleted_at IS NULL".$emergencyWhere." GROUP BY emergency_request.id ORDER BY emergency_request.id DESC";
$emergencyStatement=$pdo->prepare($emergencySql);
$emergencyStatement->execute($_SESSION['USER_TYPE'] === 'Admin' ? array() : array(':user_id'=>$LoginReGiSterSession));
function emergencyStatusBadge($status){$map=array('receiver_pending'=>array('warning','Receiver acknowledgement'),'reference_pending'=>array('info','Reference acknowledgement'),'completed'=>array('success','Ready for requisition'),'reconciled'=>array('secondary','Finalized in Requisition'),'finalized'=>array('secondary','Finalized in Requisition'));return isset($map[$status])?$map[$status]:array('secondary',ucwords(str_replace('_',' ',$status)));}
?>
<section class="content"><div class="card"><div class="card-header"><h3 class="card-title">Emergency Requests</h3><div class="card-tools"><a href="?Emergency_Request_Create" class="btn btn-danger"><i class="fas fa-bolt"></i> Create Emergency Request</a></div></div><div class="card-body p-0"><div class="table-responsive"><table id="example1" class="table table-bordered table-striped"><thead><tr><th>SL</th><th>Request No</th><th>Date</th><th>Project / Store</th><th>Receiver</th><th>Reference</th><th>Items</th><th>Created By</th><th>Status</th><th>Option</th></tr></thead><tbody><?php $serial=1;while($request=$emergencyStatement->fetch()){ $badge=emergencyStatusBadge($request['status']); ?><tr data-product-ids="<?php echo productUsageFilterIds($pdo, 'emergency', $request['id']); ?>"><td><?php echo $serial++; ?></td><td><a href="?Emergency_Request_Detail/<?php echo (int)$request['id']; ?>"><?php echo htmlspecialchars($request['request_no']); ?></a></td><td><?php echo date('d-m-Y',strtotime($request['date'])); ?></td><td><?php echo htmlspecialchars($request['project_name']); ?><br><small class="text-muted"><?php echo htmlspecialchars($request['store_name']); ?></small></td><td><?php echo htmlspecialchars($request['receiver_name']); ?></td><td><?php echo htmlspecialchars($request['reference_name']); ?></td><td><?php echo (int)$request['item_count']; ?> products<br><small class="text-muted">Qty: <?php echo rtrim(rtrim(number_format($request['total_quantity'],4,'.',''),'0'),'.'); ?></small></td><td><?php echo htmlspecialchars($request['creator_name'] ?: 'Unknown'); ?></td><td><span class="badge badge-<?php echo $badge[0]; ?>"><?php echo $badge[1]; ?></span></td><td><a class="btn btn-primary btn-sm" href="?Emergency_Request_Detail/<?php echo (int)$request['id']; ?>"><i class="fas fa-eye"></i> View</a></td></tr><?php } ?></tbody></table></div></div></div></section>
